mapper.delete:
DELETE FROM USER_LIKES
WHERE USER_ID = #{userId}
AND STORE_ID = #{storeId}

mapper.select:
SELECT COUNT(*)
FROM USER_LIKES
WHERE USER_ID = #{userId}
AND STORE_ID = #{storeId}

mapper.update:
UPDATE STORE
SET LIKES_COUNT = (
    SELECT COUNT(*)
    FROM USER_LIKES
    WHERE STORE_ID = #{storeId}
)
WHERE STORE_ID = #{storeId}

